// assets/script/PLK.ts
import EventDispatcher from "./utils/EventDispatcher";
import { GameData } from "./data/GameData";
import UIManager from "./manager/UIManager";
import { Managers } from "./Managers";
import { GameUserInfo } from "./data/GameUserInfo";
import logger from "./utils/logger";
import { MessageFlag } from "./manager/MessageFlag";
import { director, Game, game, resources, Sprite, SpriteFrame } from "cc";
import { WsManager } from "./manager/Websocketmanager";
import Sensor from "./utils/sensore";
import { DeviceUtils } from "./utils/DeviceUtils";
import TicketData from "./data/TicketData";
import { ActionQueue } from "./manager/ActionQueue";
import WakeLock from "./utils/WakeLock";

import { ScratchSound } from "./scratch/ScratchSound";

import * as GameApi from './api/GameApi';
import { AudioManager } from './manager/AudioManager';

export default class PLK {
    static event = new EventDispatcher();
    static gameData = new GameData();
    static res = Managers.res;
    static ui = new UIManager();
    static userInfo = new GameUserInfo();
    static sensor = new Sensor();
    static ticketData = new TicketData();
    static actionQueue = new ActionQueue();
    static wakeLock = new WakeLock();
    static scratchSound = new ScratchSound();

    private delayTimer: number = null;

    static init() {
        PLK.gameData.initConfig();
        PLK.gameData.getUrlParams();
        PLK.onVisibilityChange()
        PLK.sensor.init();

        // 将 PLK 暴露到全局，以便 menu-bundle 可以访问
        if (typeof window !== 'undefined') {
            (window as any).PLK = PLK;
            (window as any).GameApi = GameApi;
            (window as any).AudioManager = AudioManager;
        }
        if (typeof globalThis !== 'undefined') {
            (globalThis as any).PLK = PLK;
            (globalThis as any).GameApi = GameApi;
            (globalThis as any).AudioManager = AudioManager;
        }
    }

    // 进入游戏场景后进行预加载的节点
    // 优先预加载 WinPopUp，其它弹窗按较低优先级分批静默后台预加载
    static preloadPopUp() {
        // 最高优先级：WinPopUp
        const highPriorityPath = "prefab/WinPopUp";
        PLK.ui.preloadScene(highPriorityPath, (progress) => {
            // logger.log('WinPopUp 预加载进度', progress);
        });

        // 低优先级：其他二级弹窗，分批静默后台预加载，避免集中卡顿
        const lowPriorityList = [
            "prefab/ExitPopup",
            "prefab/Trajectory",
            "menu-bundle:resources/prefab/BundleMenu",
        ];

        const baseDelay = 800; // 毫秒，首个低优先级弹窗的延迟时间

        lowPriorityList.forEach((path, index) => {
            const delay = baseDelay * (index + 1);
            setTimeout(() => {
                PLK.ui.preloadScene(path, (progress) => {
                    // logger.log('后台预加载进度', path, progress);
                });
            }, delay);
        });
    }

    static exitGame() {
        // 根据params的callbackUrl退出游戏
        PLK.sensor.gameLeave();
        PLK.gameData.isExitGame = true;
        logger.log('执行退出游戏')
        PLK.event.emit(MessageFlag.EXIT_GAME)
        const callbackUrl = PLK.gameData.urlParams.callbackUrl;
        if (callbackUrl) {
            window.location.href = callbackUrl;
            logger.log('退出游戏', callbackUrl)
        }
    }

    static freeze() {
        // 暂停游戏
        game.pause()
        logger.log('整个游戏已冻结');
    }

    static unfreeze() {
        // 恢复游戏
        game.resume()
        logger.log('整个游戏已解冻');
    }

    private static onVisibilityChange() {
        game.on(Game.EVENT_HIDE, () => {
            logger.log('页面隐藏')
        })
        game.on(Game.EVENT_SHOW, () => {
            logger.log('页面显示')
            // 检查ws连接状态，如果被踢下线，则不进行重连，否则重连
            if (!PLK.gameData.isKickOff && !WsManager.getInstance().isConnected()) {
                // 执行ws重连
                WsManager.getInstance().reconnect()
            }
        })
    }

    // 根据当前设备类型加载背景图，texture/h5 或 texture/pc
    static loadBackground(sprite: Sprite) {
        const deviceType = DeviceUtils.isMobile() ? 'h5' : 'pc';
        if (deviceType === 'h5') {
            resources.load('texture/h5', (err, texture) => {
                if (err) return;
                sprite.spriteFrame = texture as SpriteFrame;
            });
        } else {
            resources.load('texture/pc', (err, texture) => {
                if (err) return;
                sprite.spriteFrame = texture as SpriteFrame;
            });
        }
    }

    static preloadUI() {
        // 循环进行预加载
        const uiList = ["prefab/GameRecords", "prefab/CardDetail", "prefab/OtherGames", "prefab/HonorBoard"]
        uiList.forEach(item => {
            PLK.ui.preloadScene(item, (progress) => {
                // logger.log('预加载进度', item, progress)
            });
        });
    }

    // 跳转新游戏
    static switchGame() {
        const gameId = PLK.gameData.turnToGameId;
        let path = new URLSearchParams(window.location.search);
        path.set('gameId', gameId);

        // 跳转规则是把playtype正则去掉特使符号，然后转为小写
        const _gamePath = PLK.gameData.turnToPlayType.replace(/[^a-zA-Z0-9]/g, '').toLowerCase();
        let newGamePath = `${PLK.gameData.config.otherGamePath}/${_gamePath}?${path.toString()}`;
        logger.log('跳转新游戏地址', newGamePath)
        // 跳转新游戏
        window.location.href = `${PLK.gameData.config.otherGamePath}/${_gamePath}?${path.toString()}`;
    }
}